 1→import { useState } from "react";
 2→import { useApp, useInput } from "ink";
 3→import type { SessionInfo } from "./api.js";
 4→import { SessionPicker } from "./SessionPicker.js";
 5→import { MessageView } from "./MessageView.js";
 6→
 7→type View = { kind: "picker" } | { kind: "session"; session: SessionInfo };
 8→
 9→export function App() {
10→  const { exit } = useApp();
11→  const [view, setView] = useState<View>({ kind: "picker" });
12→
13→  useInput((input) => {
14→    if (input === "q" && view.kind === "picker") {
15→      exit();
16→    }
17→  });
18→
19→  if (view.kind === "session") {
20→    return (
21→      <MessageView sessionPath={view.session.path} onBack={() => setView({ kind: "picker" })} />
22→    );
23→  }
24→
25→  return <SessionPicker onSelect={(session) => setView({ kind: "session", session })} />;
26→}
