 1→/** HTTP API client for the Claude Code Trace backend (port 11423). */
 2→
 3→// Types are shared with the main Tauri UI.
 4→export type {
 5→  SessionInfo,
 6→  DisplayMessage,
 7→  DisplayItem,
 8→  LoadResult,
 9→  SessionMeta,
10→  SessionTotals,
11→} from "../../shared/types.js";
12→
13→import type { SessionInfo, LoadResult } from "../../shared/types.js";
14→
15→export interface SettingsResponse {
16→  projects_dir: string | null;
17→  default_dir: string;
18→}
19→
20→const API = "http://127.0.0.1:11423";
21→
22→async function get<T>(path: string): Promise<T> {
23→  const res = await fetch(`${API}${path}`);
24→  if (!res.ok) throw new Error(`API ${path}: ${res.statusText}`);
25→  return res.json() as Promise<T>;
26→}
27→
28→async function post<T>(path: string, body?: unknown): Promise<T> {
29→  const res = await fetch(`${API}${path}`, {
30→    method: "POST",
31→    headers: { "Content-Type": "application/json" },
32→    body: body ? JSON.stringify(body) : undefined,
33→  });
34→  if (!res.ok) throw new Error(`API ${path}: ${res.statusText}`);
35→  const text = await res.text();
36→  return text ? (JSON.parse(text) as T) : (undefined as T);
37→}
38→
39→export const api = {
40→  getSettings: () => get<SettingsResponse>("/api/settings"),
41→  getProjectDirs: () => get<string[]>("/api/project-dirs"),
42→  discoverSessions: (dirs: string[]) =>
43→    get<SessionInfo[]>(`/api/sessions?dirs=${encodeURIComponent(dirs.join(","))}`),
44→  loadSession: (path: string) => post<LoadResult>("/api/session/load", { path }),
45→  watchSession: (path: string) => post<void>("/api/session/watch", { path }),
46→  unwatchSession: () => post<void>("/api/session/unwatch"),
47→};
