  1→import { useState, useEffect } from "react";
  2→import { Box, Text, useInput } from "ink";
  3→import { Spinner } from "@inkjs/ui";
  4→import { api, type SessionInfo } from "./api.js";
  5→import { formatTokens, formatCost, timeAgo, truncate } from "../../shared/format.js";
  6→
  7→interface SessionPickerProps {
  8→  onSelect: (session: SessionInfo) => void;
  9→}
 10→
 11→export function SessionPicker({ onSelect }: SessionPickerProps) {
 12→  const [sessions, setSessions] = useState<SessionInfo[]>([]);
 13→  const [loading, setLoading] = useState(true);
 14→  const [selected, setSelected] = useState(0);
 15→  const [error, setError] = useState("");
 16→
 17→  useEffect(() => {
 18→    (async () => {
 19→      try {
 20→        const dirs = await api.getProjectDirs();
 21→        if (dirs.length === 0) {
 22→          setError("No project directories found. Run the desktop app first to configure.");
 23→          setLoading(false);
 24→          return;
 25→        }
 26→        const list = await api.discoverSessions(dirs);
 27→        setSessions(list);
 28→      } catch (e) {
 29→        setError(`Cannot connect to backend. Is the app running?\n${e}`);
 30→      }
 31→      setLoading(false);
 32→    })();
 33→  }, []);
 34→
 35→  useInput((input, key) => {
 36→    if (loading || sessions.length === 0) return;
 37→    if (input === "j" || key.downArrow) {
 38→      setSelected((i) => Math.min(i + 1, sessions.length - 1));
 39→    } else if (input === "k" || key.upArrow) {
 40→      setSelected((i) => Math.max(i - 1, 0));
 41→    } else if (key.return) {
 42→      onSelect(sessions[selected]);
 43→    }
 44→  });
 45→
 46→  if (loading) {
 47→    return (
 48→      <Box padding={1}>
 49→        <Spinner label="Discovering sessions..." />
 50→      </Box>
 51→    );
 52→  }
 53→
 54→  if (error) {
 55→    return (
 56→      <Box padding={1}>
 57→        <Text color="red">{error}</Text>
 58→      </Box>
 59→    );
 60→  }
 61→
 62→  // Show a window of sessions around the selection
 63→  const windowSize = process.stdout.rows ? process.stdout.rows - 4 : 20;
 64→  const half = Math.floor(windowSize / 2);
 65→  let start = Math.max(0, selected - half);
 66→  const end = Math.min(sessions.length, start + windowSize);
 67→  if (end - start < windowSize) start = Math.max(0, end - windowSize);
 68→  const visible = sessions.slice(start, end);
 69→
 70→  return (
 71→    <Box flexDirection="column" padding={1}>
 72→      <Box marginBottom={1}>
 73→        <Text bold>Sessions ({sessions.length}) — j/k navigate, Enter open, q quit</Text>
 74→      </Box>
 75→      {visible.map((s, i) => {
 76→        const idx = start + i;
 77→        const isSelected = idx === selected;
 78→        return (
 79→          <Box key={s.path}>
 80→            <Text color={isSelected ? "blue" : undefined} bold={isSelected} inverse={isSelected}>
 81→              {isSelected ? " ▸ " : "   "}
 82→              {s.is_ongoing ? "● " : "  "}
 83→              <Text dimColor={!isSelected}>{truncate(s.first_message || s.session_id, 50)}</Text>
 84→              <Text dimColor> {formatTokens(s.total_tokens)} tok</Text>
 85→              <Text dimColor color="yellow">
 86→                {" "}
 87→                {formatCost(s.cost_usd)}
 88→              </Text>
 89→              <Text dimColor> {timeAgo(s.mod_time)}</Text>
 90→              {s.model ? (
 91→                <Text dimColor color="cyan">
 92→                  {" "}
 93→                  {s.model.split("-")[0]}
 94→                </Text>
 95→              ) : null}
 96→            </Text>
 97→          </Box>
 98→        );
 99→      })}
100→    </Box>
101→  );
102→}
