  1→import { useState, useEffect, useCallback } from "react";
  2→import { Box, Text, useInput } from "ink";
  3→import { Spinner } from "@inkjs/ui";
  4→import { api, type DisplayMessage } from "./api.js";
  5→import { useSSE } from "./useSSE.js";
  6→import { formatTokens, formatDuration, truncate } from "../../shared/format.js";
  7→
  8→interface MessageViewProps {
  9→  sessionPath: string;
 10→  onBack: () => void;
 11→}
 12→
 13→function roleColor(role: string): string {
 14→  switch (role) {
 15→    case "claude":
 16→      return "magenta";
 17→    case "user":
 18→      return "green";
 19→    case "system":
 20→      return "yellow";
 21→    default:
 22→      return "white";
 23→  }
 24→}
 25→
 26→function roleIcon(role: string): string {
 27→  switch (role) {
 28→    case "claude":
 29→      return "🤖";
 30→    case "user":
 31→      return "👤";
 32→    case "system":
 33→      return "⚙️";
 34→    default:
 35→      return "  ";
 36→  }
 37→}
