 39→export function MessageView({ sessionPath, onBack }: MessageViewProps) {
 40→  const [messages, setMessages] = useState<DisplayMessage[]>([]);
 41→  const [ongoing, setOngoing] = useState(false);
 42→  const [meta, setMeta] = useState({ cwd: "", git_branch: "", permission_mode: "" });
 43→  const [totals, setTotals] = useState({ total_tokens: 0, cost_usd: 0, model: "" });
 44→  const [loading, setLoading] = useState(true);
 45→  const [selected, setSelected] = useState(0);
 46→  const [expanded, setExpanded] = useState<Set<number>>(new Set());
 47→
 48→  useEffect(() => {
 49→    (async () => {
 50→      try {
 51→        const result = await api.loadSession(sessionPath);
 52→        setMessages(result.messages);
 53→        setOngoing(result.ongoing);
 54→        setMeta(result.meta);
 55→        setTotals(result.session_totals);
 56→        setSelected(result.messages.length - 1);
 57→        await api.watchSession(sessionPath);
 58→      } catch {
 59→        // ignore
 60→      }
 61→      setLoading(false);
 62→    })();
 63→    return () => {
 64→      api.unwatchSession().catch(() => {});
 65→    };
 66→  }, [sessionPath]);
 67→
 68→  // Live updates via SSE
 69→  useSSE<{
 70→    messages: DisplayMessage[];
 71→    ongoing: boolean;
 72→    permission_mode: string;
 73→    session_totals: { total_tokens: number; cost_usd: number; model: string };
 74→  }>(
 75→    "session-update",
 76→    useCallback((payload) => {
 77→      setMessages(payload.messages);
 78→      setOngoing(payload.ongoing);
 79→      setTotals(payload.session_totals);
 80→      if (payload.permission_mode) {
 81→        setMeta((m) => ({ ...m, permission_mode: payload.permission_mode }));
 82→      }
 83→    }, []),
 84→  );
 85→
 86→  const toggle = useCallback((idx: number) => {
 87→    setExpanded((prev) => {
 88→      const next = new Set(prev);
 89→      if (next.has(idx)) next.delete(idx);
 90→      else next.add(idx);
 91→      return next;
 92→    });
 93→  }, []);
 94→
 95→  useInput((input, key) => {
 96→    if (input === "q" || key.escape) {
 97→      onBack();
 98→    } else if (input === "j" || key.downArrow) {
 99→      setSelected((i) => Math.min(i + 1, messages.length - 1));
100→    } else if (input === "k" || key.upArrow) {
101→      setSelected((i) => Math.max(i - 1, 0));
102→    } else if (key.tab) {
103→      toggle(selected);
104→    } else if (input === "e") {
105→      // Expand all Claude messages
106→      const all = new Set<number>();
107→      messages.forEach((m, i) => {
108→        if (m.role === "claude") all.add(i);
109→      });
110→      setExpanded(all);
111→    } else if (input === "c") {
112→      setExpanded(new Set());
113→    } else if (input === "G") {
114→      setSelected(messages.length - 1);
115→    } else if (input === "g") {
116→      setSelected(0);
117→    }
118→  });
119→
120→  if (loading) {
121→    return (
122→      <Box padding={1}>
123→        <Spinner label="Loading session..." />
124→      </Box>
125→    );
126→  }
127→
128→  const cols = process.stdout.columns || 80;
129→  const windowSize = (process.stdout.rows || 24) - 6;
130→
131→  // Info bar
132→  const projectName = meta.cwd.split("/").pop() || "";
133→  const branch = meta.git_branch || "";
134→
135→  // Window around selection
136→  let start = Math.max(0, selected - Math.floor(windowSize / 2));
137→  const end = Math.min(messages.length, start + windowSize);
138→  if (end - start < windowSize) start = Math.max(0, end - windowSize);
139→  const visible = messages.slice(start, end);
140→
141→  return (
142→    <Box flexDirection="column">
143→      {/* Info bar */}
144→      <Box paddingX={1} gap={2}>
145→        <Text bold color="cyan">
146→          {projectName}
147→        </Text>
148→        {branch ? <Text dimColor>{branch}</Text> : null}
149→        <Text dimColor>{formatTokens(totals.total_tokens)} tok</Text>
150→        <Text dimColor color="yellow">
151→          ${totals.cost_usd.toFixed(2)}
152→        </Text>
153→        {ongoing ? (
154→          <Text color="green" bold>
155→            {" "}
156→            ● active
157→          </Text>
158→        ) : null}
159→      </Box>
160→
161→      {/* Messages */}
162→      <Box flexDirection="column" paddingX={1}>
163→        {visible.map((msg, i) => {
164→          const idx = start + i;
165→          const isSelected = idx === selected;
166→          const isExpanded = expanded.has(idx);
167→          const contentWidth = cols - 12;
168→
169→          return (
170→            <Box key={idx} flexDirection="column">
171→              <Box>
172→                <Text inverse={isSelected} bold={isSelected} color={roleColor(msg.role)}>
173→                  {isSelected ? "▸" : " "}
174→                  {roleIcon(msg.role)} {msg.role.padEnd(7)}
175→                </Text>
176→                <Text dimColor={!isSelected}> {truncate(msg.content, contentWidth - 30)}</Text>
177→                {msg.tool_call_count > 0 && (
178→                  <Text dimColor color="yellow">
179→                    {" "}
180→                    ⚙{msg.tool_call_count}
181→                  </Text>
182→                )}
183→                {msg.tokens_raw > 0 && <Text dimColor> {formatTokens(msg.tokens_raw)}</Text>}
184→                {msg.duration_ms > 0 && <Text dimColor> {formatDuration(msg.duration_ms)}</Text>}
185→              </Box>
186→
187→              {/* Expanded: show items */}
188→              {isExpanded && msg.items.length > 0 && (
189→                <Box flexDirection="column" paddingLeft={4} marginBottom={1}>
190→                  {msg.items.map((item) => (
191→                    <Box key={`${item.item_type}-${item.tool_name || item.text.slice(0, 20)}`}>
192→                      <Text dimColor>
193→                        {item.item_type === "ToolCall" ? (
194→                          <Text color={item.tool_error ? "red" : "blue"}>
195→                            ⚙ {item.tool_name}
196→                            {item.tool_summary
197→                              ? ` — ${truncate(item.tool_summary, contentWidth - 20)}`
198→                              : ""}
199→                          </Text>
200→                        ) : item.item_type === "Thinking" ? (
201→                          <Text color="gray">💭 {truncate(item.text, contentWidth - 10)}</Text>
202→                        ) : item.item_type === "Output" ? (
203→                          <Text>{truncate(item.text, contentWidth - 10)}</Text>
204→                        ) : (
205→                          <Text color="gray">
206→                            {item.item_type}: {truncate(item.text, contentWidth - 20)}
207→                          </Text>
208→                        )}
209→                      </Text>
210→                    </Box>
211→                  ))}
212→                </Box>
213→              )}
214→            </Box>
215→          );
216→        })}
217→      </Box>
218→
219→      {/* Status bar */}
220→      <Box paddingX={1} gap={2}>
221→        <Text dimColor>
222→          j/k nav Tab expand e/c all G/g jump q back {selected + 1}/{messages.length}
223→        </Text>
224→      </Box>
225→    </Box>
226→  );
227→}
