 1→import { useEffect, useRef } from "react";
 2→import { EventSource } from "eventsource";
 3→
 4→const API = "http://127.0.0.1:11423";
 5→
 6→/** Subscribe to SSE events from the Rust backend. */
 7→export function useSSE<T>(event: string, handler: (payload: T) => void) {
 8→  const handlerRef = useRef(handler);
 9→  handlerRef.current = handler;
10→
11→  useEffect(() => {
12→    const source = new EventSource(`${API}/api/events`);
13→    const onMessage = (e: MessageEvent) => {
14→      try {
15→        handlerRef.current(JSON.parse(e.data) as T);
16→      } catch {
17→        // ignore malformed events
18→      }
19→    };
20→    source.addEventListener(event, onMessage as EventListener);
21→    return () => {
22→      source.removeEventListener(event, onMessage as EventListener);
23→      source.close();
24→    };
25→  }, [event]);
26→}
