 7→// Intercept all link clicks and open external URLs in the system browser
 8→document.addEventListener("click", (e) => {
 9→  const anchor = (e.target as HTMLElement).closest("a");
10→  if (!anchor) return;
11→  const href = anchor.getAttribute("href");
12→  if (href && (href.startsWith("http://") || href.startsWith("https://"))) {
13→    e.preventDefault();
14→    openUrl(href);
15→  }
16→});
17→
18→const rootEl = document.getElementById("root");
19→if (!rootEl) throw new Error("Missing #root element");
20→
21→createRoot(rootEl).render(
22→  <StrictMode>
23→    <App />
24→  </StrictMode>,
25→);
