 1→/**
 2→ * Pure formatting utilities shared between Tauri UI and TUI.
 3→ * No React, DOM, or framework dependencies.
 4→ */
 5→
 6→/** Formats a token count: 1234 -> "1.2k", 1234567 -> "1.2M" */
 7→export function formatTokens(n: number): string {
 8→  if (n >= 1_000_000) return (n / 1_000_000).toFixed(1) + "M";
 9→  if (n >= 1_000) return (n / 1_000).toFixed(1) + "k";
10→  return String(n);
11→}
12→
13→/** Formats USD cost: 1.5 -> "$1.50" */
14→export function formatCost(usd: number): string {
15→  return "$" + usd.toFixed(2);
16→}
17→
18→/** Formats duration: 1500 -> "1.5s", 90000 -> "1m 30s" */
19→export function formatDuration(ms: number): string {
20→  if (ms < 1000) return `${ms}ms`;
21→  const s = ms / 1000;
22→  if (s < 60) return `${s.toFixed(1)}s`;
23→  const m = Math.floor(s / 60);
24→  const rem = Math.floor(s % 60);
25→  return rem > 0 ? `${m}m ${rem}s` : `${m}m`;
26→}
27→
28→/** Truncate string to max length with ellipsis, collapsing newlines. */
29→export function truncate(s: string, max: number): string {
30→  const line = s.replace(/\n/g, " ").trim();
31→  return line.length > max ? line.slice(0, max - 1) + "…" : line;
32→}
33→
34→/** Relative time: "3m ago", "2h ago", "5d ago" */
35→export function timeAgo(iso: string): string {
36→  const ms = Date.now() - new Date(iso).getTime();
37→  const mins = Math.floor(ms / 60000);
38→  if (mins < 1) return "now";
39→  if (mins < 60) return `${mins}m ago`;
40→  const hrs = Math.floor(mins / 60);
41→  if (hrs < 24) return `${hrs}h ago`;
42→  const days = Math.floor(hrs / 24);
43→  return `${days}d ago`;
44→}
