 28→export function SessionPicker({
 29→  sessions,
 30→  loading,
 31→  searchQuery,
 32→  selectedIndex,
 33→  onSelect,
 34→  onSearchChange,
 35→  onSelectIndex,
 36→}: SessionPickerProps) {
 37→  const listRef = useRef<HTMLDivElement>(null);
 38→  const selectedRef = useScrollToSelected(selectedIndex);
 39→  const searchRef = useRef<HTMLInputElement>(null);
 40→
 41→  const dateGroups = groupByDate(sessions);
 42→
 43→  const { totalTokens, totalCost } = useMemo(() => {
 44→    let tokens = 0;
 45→    let cost = 0;
 46→    for (const s of sessions) {
 47→      tokens += s.total_tokens;
 48→      cost += s.cost_usd;
 49→    }
 50→    return { totalTokens: tokens, totalCost: cost };
 51→  }, [sessions]);
 52→
 53→  // Build flat list for index tracking
 54→  let flatIndex = 0;
 55→
 56→  return (
 57→    <div className="picker">
 58→      <div className="picker__header">
 59→        <div className="picker__title">
 60→          Sessions
 61→          {totalTokens > 0 && (
 62→            <span className="picker__total-tokens">
 63→              <TokensIcon /> {formatTokens(totalTokens)} tok
 64→            </span>
 65→          )}
 66→          {totalCost > 0 && (
