 21→export function MessageList({
 22→  messages,
 23→  selectedIndex,
 24→  expandedSet,
 25→  ongoing,
 26→  onSelect,
 27→  onToggle,
 28→  onOpenDetail,
 29→  viewActionsRef,
 30→  onExpandAll,
 31→  onCollapseAll,
 32→}: MessageListProps) {
 33→  useRegisterViewActions(viewActionsRef, { expandAll: onExpandAll, collapseAll: onCollapseAll });
 34→  const listRef = useAutoScroll<HTMLDivElement>(messages.length);
 35→  const selectedRef = useScrollToSelected(selectedIndex);
 36→
 37→  const handleClick = useCallback(
 38→    (index: number) => {
 39→      if (selectedIndex === index) {
 40→        onToggle(index);
 41→      } else {
 42→        onSelect(index);
 43→      }
 44→    },
 45→    [selectedIndex, onSelect, onToggle],
 46→  );
 47→
 48→  // Chronological order: oldest messages first
 49→  const ordered = useMemo(() => {
 50→    const indices: number[] = [];
 51→    for (let i = 0; i < messages.length; i++) {
 52→      indices.push(i);
 53→    }
 54→    return indices;
 55→  }, [messages.length]);
 56→
 57→  if (messages.length === 0) {
 58→    return (
 59→      <div className="message-list">
 60→        <div className="message-list__empty">No messages loaded</div>
 61→      </div>
 62→    );
 63→  }
 64→
 65→  return (
 66→    <div className="message-list" ref={listRef}>
 67→      {ordered.map((i) => {
 68→        const msg = messages[i];
 69→        if (msg.role === "compact") {
 70→          return <CompactSeparator key={i} content={msg.content} />;
 71→        }
 72→
 73→        const isSelected = i === selectedIndex;
 74→        const isLast = i === messages.length - 1;
 75→
 76→        return (
 77→          <MessageItem
 78→            key={i}
 79→            ref={isSelected ? selectedRef : undefined}
 80→            message={msg}
 81→            index={i}
 82→            isSelected={isSelected}
 83→            isExpanded={expandedSet.has(i)}
 84→            onClick={handleClick}
 85→            onOpenDetail={onOpenDetail}
 86→            isOngoing={isLast && ongoing}
 87→          />
 88→        );
 89→      })}
 90→    </div>
 91→  );
 92→}
 93→
 94→function CompactSeparator({ content }: { content: string }) {
 95→  return (
 96→    <div className="compact-separator">
 97→      <div className="compact-separator__line">
 98→        <span className="compact-separator__rule" />
 99→        <span>{content}</span>
100→        <span className="compact-separator__rule" />
101→      </div>
102→    </div>
103→  );
104→}
