  1→import { useState, useMemo, useCallback, useRef, useLayoutEffect, useEffect } from "react";
  2→import ReactMarkdown from "react-markdown";
  3→import type { DisplayMessage, DisplayItem } from "../types";
  4→import { shortModel, formatTokens, formatDuration, formatExactTime } from "../lib/format";
  5→import { getModelColor, getTeamColor } from "../lib/theme";
  6→import { MessageItem } from "./MessageItem";
  7→import { DetailItem } from "./DetailItem";
  8→import { useToggleSet } from "../hooks/useToggleSet";
  9→import { useScrollToSelected } from "../hooks/useScrollToSelected";
 10→import { useAutoScroll } from "../hooks/useAutoScroll";
 11→import { useKeyboard } from "../hooks/useKeyboard";
 12→import { useRegisterViewActions, type ViewActionsRef } from "../hooks/useViewActions";
 13→import { BackButton } from "./BackButton";
 14→import { ResizeHandle } from "./ResizeHandle";
 15→import { OngoingDots } from "./OngoingDots";
 16→import { IoMdCloseCircle } from "react-icons/io";
 17→import { ClaudeIcon } from "./Icons";
 18→
 19→/* ─── Helpers ─── */
 20→
 21→/** Recursively find a DisplayItem by agent_id in a nested item tree. */
 22→function findItemByAgentId(items: DisplayItem[], agentId: string): DisplayItem | undefined {
 23→  for (const item of items) {
 24→    if (item.agent_id === agentId) return item;
 25→    for (const subMsg of item.subagent_messages) {
 26→      const found = findItemByAgentId(subMsg.items, agentId);
 27→      if (found) return found;
 28→    }
 29→  }
 30→  return undefined;
 31→}
 32→
 33→/* ─── Panel stack types ─── */
 34→
 35→type PanelEntry =
 36→  | { kind: "agent-list"; item: DisplayItem; key: string }
 37→  | { kind: "agent-detail"; item: DisplayItem; msg: DisplayMessage; key: string };
 38→
 39→/** Imperative handle exposed by each navigable column */
 40→interface ColumnNav {
 41→  moveUp: () => void;
 42→  moveDown: () => void;
 43→  toggle: () => void;
 44→  enter: () => void;
 45→  itemCount: () => number;
 46→  expandAll: () => void;
 47→  collapseAll: () => void;
 48→}
 49→
 50→interface MessageDetailProps {
 51→  message: DisplayMessage;
 52→  ongoing?: boolean;
 53→  onBack: () => void;
 54→  viewActionsRef: ViewActionsRef;
 55→}
 56→
 57→export function MessageDetail({
 58→  message: msg,
 59→  ongoing,
 60→  onBack,
 61→  viewActionsRef,
 62→}: MessageDetailProps) {
 63→  const {
 64→    set: expandedItems,
 65→    toggle: toggleItem,
 66→    addAll: expandAllItems,
 67→    clear: clearItems,
 68→  } = useToggleSet();
 69→  const [selectedItem, setSelectedItem] = useState(0);
 70→  const scrollRef = useScrollToSelected(selectedItem);
 71→  const [panelStack, setPanelStack] = useState<PanelEntry[]>([]);
 72→  const [columnWidths, setColumnWidths] = useState<(number | null)[]>([null]);
 73→  const [focusedColumn, setFocusedColumn] = useState(0); // 0 = main, 1+ = panel index + 1
 74→  const bodyRef = useRef<HTMLDivElement>(null);
 75→  useAutoScroll(msg.items.length, bodyRef);
 76→  const savedScroll = useRef<number | null>(null);
 77→  const panelRefs = useRef<Map<number, ColumnNav>>(new Map());
 78→
 79→  const detailExpandAll = useCallback(() => {
 80→    if (focusedColumn === 0) {
 81→      expandAllItems(msg.items.map((_, i) => i));
 82→    } else {
 83→      panelRefs.current.get(focusedColumn - 1)?.expandAll();
 84→    }
 85→  }, [msg.items, expandAllItems, focusedColumn]);
 86→
 87→  const detailCollapseAll = useCallback(() => {
 88→    if (focusedColumn === 0) {
 89→      clearItems();
 90→    } else {
 91→      panelRefs.current.get(focusedColumn - 1)?.collapseAll();
 92→    }
 93→  }, [clearItems, focusedColumn]);
 94→
 95→  useRegisterViewActions(viewActionsRef, {
 96→    expandAll: detailExpandAll,
 97→    collapseAll: detailCollapseAll,
 98→  });
 99→
100→  // Keep panel stack items fresh when the session watcher sends updated data.
101→  // Without this, subagent_ongoing and subagent_messages would be stale.
102→  // Only updates state when something meaningful changed to avoid extra re-renders.
103→  useEffect(() => {
104→    if (panelStack.length === 0) return;
105→    setPanelStack((prev) => {
106→      let changed = false;
107→      const next = prev.map((entry) => {
108→        if (!entry.item.agent_id) return entry;
109→        const fresh = findItemByAgentId(msg.items, entry.item.agent_id);
110→        if (!fresh) return entry;
111→        // Skip if nothing meaningful changed.
112→        if (
113→          fresh.subagent_ongoing === entry.item.subagent_ongoing &&
114→          fresh.subagent_messages.length === entry.item.subagent_messages.length
115→        ) {
116→          return entry;
117→        }
118→        changed = true;
119→        if (entry.kind === "agent-list") {
120→          return { ...entry, item: fresh };
121→        }
122→        // For agent-detail, also refresh the message by matching timestamp.
123→        const freshMsg =
124→          fresh.subagent_messages.find(
125→            (m) => m.timestamp === entry.msg.timestamp && m.role === entry.msg.role,
126→          ) ?? entry.msg;
127→        return { ...entry, item: fresh, msg: freshMsg };
128→      });
129→      return changed ? next : prev;
130→    });
131→  }, [msg.items, panelStack.length]);
132→
133→  useLayoutEffect(() => {
134→    if (savedScroll.current != null && bodyRef.current) {
135→      bodyRef.current.scrollTop = savedScroll.current;
136→      savedScroll.current = null;
137→    }
138→  }, [panelStack.length]);
139→
140→  const model = msg.model ? shortModel(msg.model) : "";
141→  const modelColor = msg.model ? getModelColor(msg.model) : undefined;
142→  const time = formatExactTime(msg.timestamp);
143→  const hasItems = msg.items.length > 0;
144→  const hasPanels = panelStack.length > 0;
145→
146→  // Stack manipulation
147→  const openSubagentFromMain = useCallback((item: DisplayItem) => {
148→    if (bodyRef.current) {
149→      savedScroll.current = bodyRef.current.scrollTop;
150→    }
151→    setPanelStack((prev) => {
152→      if (
153→        prev.length === 1 &&
154→        prev[0].kind === "agent-list" &&
155→        prev[0].item.agent_id === item.agent_id
156→      ) {
157→        return [];
158→      }
159→      return [{ kind: "agent-list", item, key: item.agent_id || `panel-0` }];
160→    });
161→    setColumnWidths((prev) => [prev[0]]);
162→    setFocusedColumn(1);
163→  }, []);
164→
165→  const openSubagentAt = useCallback((depth: number, item: DisplayItem) => {
166→    setPanelStack((prev) => {
167→      const next = prev.slice(0, depth + 1);
168→      next.push({ kind: "agent-list", item, key: item.agent_id || `panel-${depth + 1}` });
169→      return next;
170→    });
171→    setColumnWidths((prev) => prev.slice(0, depth + 2));
172→    setFocusedColumn(depth + 2);
173→  }, []);
174→
175→  const openDetailAt = useCallback((depth: number, detailMsg: DisplayMessage) => {
176→    setPanelStack((prev) => {
177→      const entry = prev[depth];
178→      if (!entry || entry.kind !== "agent-list") return prev;
179→      const next = prev.slice(0, depth);
180→      next.push({
181→        kind: "agent-detail",
182→        item: entry.item,
183→        msg: detailMsg,
184→        key: entry.key + ":detail",
185→      });
186→      return next;
187→    });
188→  }, []);
189→
190→  const backToListAt = useCallback((depth: number) => {
191→    setPanelStack((prev) => {
192→      const entry = prev[depth];
193→      if (!entry || entry.kind !== "agent-detail") return prev;
194→      const next = prev.slice(0, depth);
195→      next.push({
196→        kind: "agent-list",
197→        item: entry.item,
198→        key: entry.item.agent_id || `panel-${depth}`,
199→      });
200→      return next;
201→    });
202→  }, []);
203→
204→  const closeAt = useCallback((depth: number) => {
205→    setPanelStack((prev) => prev.slice(0, depth));
206→    setColumnWidths((prev) => prev.slice(0, depth + 1));
207→    setFocusedColumn((prev) => Math.min(prev, depth));
208→  }, []);
209→
210→  const setColumnWidth = useCallback((colIndex: number, width: number) => {
211→    setColumnWidths((prev) => {
212→      const next = [...prev];
213→      while (next.length <= colIndex) next.push(null);
214→      next[colIndex] = width;
215→      return next;
216→    });
217→  }, []);
218→
219→  const handleItemClick = (index: number, item: DisplayItem) => {
220→    setSelectedItem(index);
221→    setFocusedColumn(0);
222→    if (item.subagent_messages.length > 0) {
223→      openSubagentFromMain(item);
224→    } else {
225→      toggleItem(index);
226→    }
227→  };
228→
229→  const registerPanelNav = useCallback((depth: number, nav: ColumnNav | null) => {
230→    if (nav) {
231→      panelRefs.current.set(depth, nav);
232→    } else {
233→      panelRefs.current.delete(depth);
234→    }
235→  }, []);
236→
237→  // Single keyboard handler for all columns
238→  const detailKeyMap: Record<string, () => void> = {};
239→
240→  // Navigation: j/k/ArrowDown/ArrowUp/Tab/Enter dispatch to the focused column
241→  const moveDown = () => {
242→    if (focusedColumn === 0) {
243→      setSelectedItem((i) => Math.min(i + 1, msg.items.length - 1));
244→    } else {
245→      const nav = panelRefs.current.get(focusedColumn - 1);
246→      nav?.moveDown();
247→    }
248→  };
249→  const moveUp = () => {
250→    if (focusedColumn === 0) {
251→      setSelectedItem((i) => Math.max(i - 1, 0));
252→    } else {
253→      const nav = panelRefs.current.get(focusedColumn - 1);
254→      nav?.moveUp();
255→    }
256→  };
257→  detailKeyMap["j"] = moveDown;
258→  detailKeyMap["ArrowDown"] = moveDown;
259→  detailKeyMap["k"] = moveUp;
260→  detailKeyMap["ArrowUp"] = moveUp;
261→  detailKeyMap["Tab"] = () => {
262→    if (focusedColumn === 0) {
263→      const item = msg.items[selectedItem];
264→      if (item) handleItemClick(selectedItem, item);
265→    } else {
266→      const nav = panelRefs.current.get(focusedColumn - 1);
267→      nav?.toggle();
268→    }
269→  };
270→  detailKeyMap["Enter"] = () => {
271→    if (focusedColumn === 0) {
272→      const item = msg.items[selectedItem];
273→      if (item && item.subagent_messages.length > 0) {
274→        openSubagentFromMain(item);
275→      } else if (item) {
276→        toggleItem(selectedItem);
277→      }
278→    } else {
279→      const nav = panelRefs.current.get(focusedColumn - 1);
280→      nav?.enter();
281→    }
282→  };
283→
284→  // h/l or ArrowLeft/ArrowRight to switch focused column
285→  detailKeyMap["h"] = () => setFocusedColumn((c) => Math.max(0, c - 1));
286→  detailKeyMap["ArrowLeft"] = () => setFocusedColumn((c) => Math.max(0, c - 1));
287→  detailKeyMap["l"] = () => setFocusedColumn((c) => Math.min(panelStack.length, c + 1));
288→  detailKeyMap["ArrowRight"] = () => setFocusedColumn((c) => Math.min(panelStack.length, c + 1));
289→
290→  // q = go back to list
291→  detailKeyMap["q"] = onBack;
292→  // Escape = close rightmost panel, or go back
293→  detailKeyMap["Escape"] = () => {
294→    if (panelStack.length > 0) {
295→      closeAt(panelStack.length - 1);
296→    } else {
297→      onBack();
298→    }
299→  };
300→
301→  useKeyboard(detailKeyMap);
302→
303→  const mainWidthStyle =
304→    hasPanels && columnWidths[0]
305→      ? { flex: `0 0 ${columnWidths[0]}px`, maxWidth: columnWidths[0] }
306→      : undefined;
307→
308→  return (
309→    <div className={`message-detail${hasPanels ? " message-detail--split" : ""}`}>
310→      <div
311→        className={`message-detail__main${focusedColumn === 0 ? " message-detail__main--focused" : ""}`}
312→        style={mainWidthStyle}
313→        onClick={() => setFocusedColumn(0)}
314→      >
315→        <div className="message-detail__header">
316→          <BackButton onClick={onBack} />
317→          <span className="message-detail__title">
318→            {msg.role === "user" ? "User" : msg.role === "claude" ? "Claude" : "System"}
319→          </span>
320→          {model && (
321→            <span style={{ color: modelColor, fontWeight: 600, fontSize: 12 }}>{model}</span>
322→          )}
323→          {msg.subagent_label && (
324→            <span className="detail-item__subagent-badge">{msg.subagent_label}</span>
325→          )}
326→          <span className="message-detail__meta">
327→            {time}
328→            {msg.tokens_raw > 0 && (
329→              <>
330→                {" "}
331→                {"\u00B7"} {formatTokens(msg.tokens_raw)} tok
332→              </>
333→            )}
334→            {msg.duration_ms > 0 && (
335→              <>
336→                {" "}
337→                {"\u00B7"} {formatDuration(msg.duration_ms)}
338→              </>
339→            )}
340→          </span>
341→        </div>
342→
343→        <div className="message-detail__body" ref={bodyRef}>
344→          <div className="message-detail__content">
345→            {msg.content && (
346→              <div className="message-detail__text">
347→                <ReactMarkdown>{msg.content}</ReactMarkdown>
348→              </div>
349→            )}
350→            {hasItems && (
351→              <div className="detail-items">
352→                <div className="detail-items__section-label">Items ({msg.items.length})</div>
353→                {msg.items.map((item, idx) => (
354→                  <DetailItem
355→                    key={`${item.item_type}-${item.tool_name}-${item.tool_summary}-${item.duration_ms}`}
356→                    ref={idx === selectedItem ? scrollRef : undefined}
357→                    item={item}
358→                    index={idx}
359→                    isSelected={idx === selectedItem}
360→                    isExpanded={expandedItems.has(idx)}
361→                    isAgentActive={
362→                      panelStack.length > 0 &&
363→                      panelStack[0].item.agent_id === item.agent_id &&
364→                      !!item.agent_id
365→                    }
366→                    onToggle={handleItemClick}
367→                    onToggleExpand={toggleItem}
368→                    onSelect={setSelectedItem}
369→                  />
370→                ))}
371→              </div>
372→            )}
373→            {ongoing && (
374→              <div className="message-detail__ongoing">
375→                <OngoingDots />
376→              </div>
377→            )}
378→          </div>
379→        </div>
380→      </div>
381→
382→      {panelStack.map((entry, depth) => {
383→        const colWidth = columnWidths[depth + 1];
384→        const widthStyle = colWidth ? { flex: `0 0 ${colWidth}px`, maxWidth: colWidth } : undefined;
385→        const isFocused = focusedColumn === depth + 1;
386→
387→        return (
388→          <PanelColumn
389→            key={entry.key}
390→            entry={entry}
391→            depth={depth}
392→            style={widthStyle}
393→            isFocused={isFocused}
394→            panelStack={panelStack}
395→            onOpenDetail={(detailMsg) => openDetailAt(depth, detailMsg)}
396→            onBackToList={() => backToListAt(depth)}
397→            onOpenSubagent={(item) => openSubagentAt(depth, item)}
398→            onClose={() => closeAt(depth)}
399→            onResize={(w) => setColumnWidth(depth, w)}
400→            onFocus={() => setFocusedColumn(depth + 1)}
401→            onRegisterNav={(nav) => registerPanelNav(depth, nav)}
402→          />
403→        );
404→      })}
405→    </div>
406→  );
407→}
408→
409→/* ─── PanelColumn: renders ResizeHandle + either list or detail ─── */
410→
411→interface PanelColumnProps {
412→  entry: PanelEntry;
413→  depth: number;
414→  style?: React.CSSProperties;
415→  isFocused: boolean;
416→  panelStack: PanelEntry[];
417→  onOpenDetail: (msg: DisplayMessage) => void;
418→  onBackToList: () => void;
419→  onOpenSubagent: (item: DisplayItem) => void;
420→  onClose: () => void;
421→  onResize: (width: number) => void;
422→  onFocus: () => void;
423→  onRegisterNav: (nav: ColumnNav | null) => void;
424→}
425→
426→function PanelColumn({
427→  entry,
428→  depth,
429→  style,
430→  isFocused,
431→  panelStack,
432→  onOpenDetail,
433→  onBackToList,
434→  onOpenSubagent,
435→  onClose,
436→  onResize,
437→  onFocus,
438→  onRegisterNav,
439→}: PanelColumnProps) {
440→  return (
441→    <>
442→      <ResizeHandle onResize={onResize} />
443→      {entry.kind === "agent-list" ? (
444→        <AgentListColumn
445→          item={entry.item}
446→          style={style}
447→          isFocused={isFocused}
448→          onOpenDetail={onOpenDetail}
449→          onClose={onClose}
450→          onFocus={onFocus}
451→          onRegisterNav={onRegisterNav}
452→        />
453→      ) : (
454→        <AgentDetailColumn
455→          item={entry.item}
456→          msg={entry.msg}
457→          style={style}
458→          isFocused={isFocused}
459→          depth={depth}
460→          panelStack={panelStack}
461→          onOpenSubagent={onOpenSubagent}
462→          onBack={onBackToList}
463→          onClose={onClose}
464→          onFocus={onFocus}
465→          onRegisterNav={onRegisterNav}
466→        />
467→      )}
468→    </>
469→  );
470→}
471→
472→/* ─── AgentListColumn: shows agent header + message list ─── */
473→
474→interface AgentListColumnProps {
475→  item: DisplayItem;
476→  style?: React.CSSProperties;
477→  isFocused: boolean;
478→  onOpenDetail: (msg: DisplayMessage) => void;
479→  onClose: () => void;
480→  onFocus: () => void;
481→  onRegisterNav: (nav: ColumnNav | null) => void;
482→}
483→
484→function AgentListColumn({
485→  item,
486→  style,
487→  isFocused,
488→  onOpenDetail,
489→  onClose,
490→  onFocus,
491→  onRegisterNav,
492→}: AgentListColumnProps) {
493→  const messages = item.subagent_messages;
494→  const [selectedMsg, setSelectedMsg] = useState(messages.length - 1);
495→  const {
496→    set: expandedSet,
497→    toggle: toggleMsg,
498→    addAll: expandAllMsgs,
499→    clear: clearMsgs,
500→  } = useToggleSet();
501→  const listRef = useAutoScroll<HTMLDivElement>(messages.length);
502→  const selectedRef = useScrollToSelected(selectedMsg);
503→  const panelColor = item.team_color ? getTeamColor(item.team_color) : undefined;
504→
505→  const handleClick = useCallback(
506→    (index: number) => {
507→      onFocus();
508→      if (selectedMsg === index) {
509→        toggleMsg(index);
510→      } else {
511→        setSelectedMsg(index);
512→      }
513→    },
514→    [selectedMsg, toggleMsg, onFocus],
515→  );
516→
517→  // Expose navigation to parent via callback ref
518→  const navRef = useRef<ColumnNav>({
519→    moveUp: () => setSelectedMsg((i) => Math.max(i - 1, 0)),
520→    moveDown: () => setSelectedMsg((i) => Math.min(i + 1, messages.length - 1)),
521→    toggle: () => toggleMsg(selectedMsg),
522→    enter: () => {
523→      if (messages[selectedMsg]) onOpenDetail(messages[selectedMsg]);
524→    },
525→    itemCount: () => messages.length,
526→    expandAll: () => expandAllMsgs(messages.map((_, i) => i)),
527→    collapseAll: () => clearMsgs(),
528→  });
529→  navRef.current.moveUp = () => setSelectedMsg((i) => Math.max(i - 1, 0));
530→  navRef.current.moveDown = () => setSelectedMsg((i) => Math.min(i + 1, messages.length - 1));
531→  navRef.current.toggle = () => toggleMsg(selectedMsg);
532→  navRef.current.enter = () => {
533→    if (messages[selectedMsg]) onOpenDetail(messages[selectedMsg]);
534→  };
535→  navRef.current.itemCount = () => messages.length;
536→  navRef.current.expandAll = () => expandAllMsgs(messages.map((_, i) => i));
537→  navRef.current.collapseAll = () => clearMsgs();
538→
539→  // Register/unregister nav on mount/unmount
540→  useLayoutEffect(() => {
541→    onRegisterNav(navRef.current);
542→    return () => onRegisterNav(null);
543→  }, [onRegisterNav]);
544→
545→  const ordered = useMemo(() => {
546→    const indices: number[] = [];
547→    for (let i = 0; i < messages.length; i++) indices.push(i);
548→    return indices;
549→  }, [messages.length]);
550→
551→  return (
552→    <div
553→      className={`agent-panel${isFocused ? " agent-panel--focused" : ""}`}
554→      style={
555→        {
556→          ...(panelColor ? { background: `${panelColor}08` } : {}),
557→          ...style,
558→        } as React.CSSProperties
559→      }
560→      onClick={onFocus}
561→    >
562→      <AgentPanelHeader item={item} panelColor={panelColor} onClose={onClose} />
563→      <div className="agent-panel__content">
564→        <div className="agent-panel__list" ref={listRef}>
565→          {ordered.map((i) => {
566→            const msg = messages[i];
567→            if (msg.role === "compact") {
568→              return (
569→                <div key={i} className="compact-separator">
570→                  <div className="compact-separator__line">
571→                    <span className="compact-separator__rule" />
572→                    <span>{msg.content}</span>
573→                    <span className="compact-separator__rule" />
574→                  </div>
575→                </div>
576→              );
577→            }
578→            const isSelected = i === selectedMsg;
579→            const isExpanded = expandedSet.has(i);
580→            const isLast = i === messages.length - 1;
581→            return (
582→              <MessageItem
583→                key={i}
584→                ref={isSelected ? selectedRef : undefined}
585→                message={msg}
586→                index={i}
587→                isSelected={isSelected}
588→                isExpanded={isExpanded}
589→                isOngoing={isLast && item.subagent_ongoing}
590→                onClick={handleClick}
591→                onOpenDetail={(idx) => onOpenDetail(messages[idx])}
592→              />
593→            );
594→          })}
595→        </div>
596→      </div>
597→    </div>
598→  );
599→}
