617→function AgentDetailColumn({
618→  item,
619→  msg,
620→  style,
621→  isFocused,
622→  depth,
623→  panelStack,
624→  onOpenSubagent,
625→  onBack,
626→  onClose,
627→  onFocus,
628→  onRegisterNav,
629→}: AgentDetailColumnProps) {
630→  const {
631→    set: expandedItems,
632→    toggle: toggleItem,
633→    addAll: expandAllDetailItems,
634→    clear: clearDetailItems,
635→  } = useToggleSet();
636→  const [selectedItem, setSelectedItem] = useState(0);
637→  const scrollRef = useScrollToSelected(selectedItem);
638→  const detailBodyRef = useAutoScroll<HTMLDivElement>(msg.items.length);
639→  const panelColor = item.team_color ? getTeamColor(item.team_color) : undefined;
640→
641→  const model = msg.model ? shortModel(msg.model) : "";
642→  const modelColor = msg.model ? getModelColor(msg.model) : undefined;
643→  const time = formatExactTime(msg.timestamp);
644→  const hasItems = msg.items.length > 0;
645→
646→  // Check if a deeper panel is open for a given agent_id
647→  const activeAgentId = depth + 1 < panelStack.length ? panelStack[depth + 1].item.agent_id : null;
648→
649→  const handleItemClick = (index: number, clickedItem: DisplayItem) => {
650→    onFocus();
651→    setSelectedItem(index);
652→    if (clickedItem.subagent_messages.length > 0) {
653→      onOpenSubagent(clickedItem);
654→    } else {
655→      toggleItem(index);
656→    }
657→  };
658→
659→  // Expose navigation to parent via callback ref
660→  const navRef = useRef<ColumnNav>({
661→    moveUp: () => {},
662→    moveDown: () => {},
663→    toggle: () => {},
664→    enter: () => {},
665→    itemCount: () => msg.items.length,
666→    expandAll: () => expandAllDetailItems(msg.items.map((_, i) => i)),
667→    collapseAll: () => clearDetailItems(),
668→  });
669→  navRef.current.moveUp = () => setSelectedItem((i) => Math.max(i - 1, 0));
670→  navRef.current.moveDown = () => setSelectedItem((i) => Math.min(i + 1, msg.items.length - 1));
671→  navRef.current.toggle = () => {
672→    const it = msg.items[selectedItem];
673→    if (it) handleItemClick(selectedItem, it);
674→  };
675→  navRef.current.enter = () => {
676→    const it = msg.items[selectedItem];
677→    if (it && it.subagent_messages.length > 0) {
678→      onOpenSubagent(it);
679→    } else if (it) {
680→      toggleItem(selectedItem);
681→    }
682→  };
683→  navRef.current.itemCount = () => msg.items.length;
684→  navRef.current.expandAll = () => expandAllDetailItems(msg.items.map((_, i) => i));
685→  navRef.current.collapseAll = () => clearDetailItems();
686→
687→  useLayoutEffect(() => {
688→    onRegisterNav(navRef.current);
689→    return () => onRegisterNav(null);
690→  }, [onRegisterNav]);
691→
692→  return (
693→    <div
694→      className={`agent-panel${isFocused ? " agent-panel--focused" : ""}`}
695→      style={
696→        {
697→          ...(panelColor ? { background: `${panelColor}08` } : {}),
698→          ...style,
699→        } as React.CSSProperties
700→      }
701→      onClick={onFocus}
702→    >
703→      <AgentPanelHeader item={item} panelColor={panelColor} onClose={onClose} />
704→      <div className="agent-panel__content">
705→        <div className="message-detail__header" style={{ borderBottom: "1px solid var(--border)" }}>
706→          <BackButton onClick={onBack} />
707→          <span className="message-detail__title">
708→            {msg.role === "user" ? "User" : msg.role === "claude" ? "Claude" : "System"}
709→          </span>
710→          {model && (
711→            <span style={{ color: modelColor, fontWeight: 600, fontSize: 12 }}>{model}</span>
712→          )}
713→          <span className="message-detail__meta">
714→            {time}
715→            {msg.tokens_raw > 0 && (
716→              <>
717→                {" "}
718→                {"\u00B7"} {formatTokens(msg.tokens_raw)} tok
719→              </>
720→            )}
721→          </span>
722→        </div>
723→        <div className="message-detail__body" ref={detailBodyRef}>
724→          <div className="message-detail__content">
725→            {msg.content && (
726→              <div className="message-detail__text">
727→                <ReactMarkdown>{msg.content}</ReactMarkdown>
728→              </div>
729→            )}
730→            {hasItems && (
731→              <div className="detail-items">
732→                <div className="detail-items__section-label">Items ({msg.items.length})</div>
733→                {msg.items.map((di, idx) => (
734→                  <DetailItem
735→                    key={`${di.item_type}-${di.tool_name}-${di.tool_summary}-${di.duration_ms}`}
736→                    ref={idx === selectedItem ? scrollRef : undefined}
737→                    item={di}
738→                    index={idx}
739→                    isSelected={idx === selectedItem}
740→                    isExpanded={expandedItems.has(idx)}
741→                    isAgentActive={activeAgentId === di.agent_id && !!di.agent_id}
742→                    onToggle={handleItemClick}
743→                    onToggleExpand={toggleItem}
744→                    onSelect={setSelectedItem}
745→                  />
746→                ))}
747→              </div>
