  1→/**
  2→ * Safe wrapper around Tauri's `invoke`.
  3→ *
  4→ * In the Tauri webview it delegates to the real IPC bridge.
  5→ * In a plain browser it calls the Rust backend's HTTP API.
  6→ */
  7→import { invoke as tauriInvoke } from "@tauri-apps/api/core";
  8→import { isTauri } from "./isTauri";
  9→import { API_BASE } from "./config";
 10→
 11→// ---------------------------------------------------------------------------
 12→// Route map — add new commands here without touching invoke logic (OCP).
 13→// ---------------------------------------------------------------------------
 14→
 15→interface Route {
 16→  method?: "POST";
 17→  path: string | ((args: Record<string, unknown>) => string);
 18→  body?: (args: Record<string, unknown>) => unknown;
 19→}
 20→
 21→/** Declarative mapping from Tauri command names to HTTP endpoints. */
 22→const routes: Record<string, Route> = {
 23→  get_settings: { path: "/api/settings" },
 24→  set_projects_dir: {
 25→    method: "POST",
 26→    path: "/api/settings/dir",
 27→    body: (a) => ({ path: a.path ?? null }),
 28→  },
 29→  get_project_dirs: { path: "/api/project-dirs" },
 30→  discover_sessions: {
 31→    path: (a) => {
 32→      const dirs = (a.projectDirs as string[]) ?? [];
 33→      return `/api/sessions?dirs=${encodeURIComponent(dirs.join(","))}`;
 34→    },
 35→  },
 36→  load_session: {
 37→    method: "POST",
 38→    path: "/api/session/load",
 39→    body: (a) => ({ path: a.path }),
 40→  },
 41→  get_session_meta: {
 42→    path: (a) => `/api/session/meta?path=${encodeURIComponent(String(a.path ?? ""))}`,
 43→  },
 44→  watch_session: {
 45→    method: "POST",
 46→    path: "/api/session/watch",
 47→    body: (a) => ({ path: a.path }),
 48→  },
 49→  unwatch_session: { method: "POST", path: "/api/session/unwatch" },
 50→  watch_picker: {
 51→    method: "POST",
 52→    path: "/api/picker/watch",
 53→    body: (a) => ({ projectDirs: a.projectDirs }),
 54→  },
 55→  unwatch_picker: { method: "POST", path: "/api/picker/unwatch" },
 56→  get_git_info: {
 57→    path: (a) => `/api/git-info?cwd=${encodeURIComponent(String(a.cwd ?? ""))}`,
 58→  },
 59→  get_debug_log: {
 60→    path: (a) => {
 61→      const params = new URLSearchParams();
 62→      params.set("path", String(a.sessionPath ?? ""));
 63→      if (a.minLevel) params.set("minLevel", String(a.minLevel));
 64→      if (a.filterText) params.set("filterText", String(a.filterText));
 65→      return `/api/debug-log?${params}`;
 66→    },
 67→  },
 68→};
 69→
 70→// ---------------------------------------------------------------------------
 71→// HTTP transport (SRP — only handles fetch, not routing).
 72→// ---------------------------------------------------------------------------
 73→
 74→async function fetchJson<T>(url: string, init?: RequestInit): Promise<T> {
 75→  const res = await fetch(url, {
 76→    ...init,
 77→    headers: { "Content-Type": "application/json", ...init?.headers },
 78→  });
 79→  if (!res.ok) {
 80→    const body = await res.json().catch(() => ({ error: res.statusText }));
 81→    throw new Error(body.error ?? res.statusText);
 82→  }
 83→  const text = await res.text();
 84→  return text ? (JSON.parse(text) as T) : (undefined as T);
 85→}
 86→
 87→/** Resolve a route to a fetch call. */
 88→async function httpInvoke<T>(cmd: string, args?: Record<string, unknown>): Promise<T> {
 89→  const route = routes[cmd];
 90→  if (!route) {
 91→    throw new Error(`[web] Unknown command "${cmd}"`);
 92→  }
 93→  const a = args ?? {};
 94→  const path = typeof route.path === "function" ? route.path(a) : route.path;
 95→  const init: RequestInit = {};
 96→  if (route.method) init.method = route.method;
 97→  if (route.body) init.body = JSON.stringify(route.body(a));
 98→  return fetchJson<T>(`${API_BASE}${path}`, init);
 99→}
100→
101→// ---------------------------------------------------------------------------
102→// Public API
103→// ---------------------------------------------------------------------------
104→
105→/**
106→ * Drop-in replacement for `import { invoke } from "@tauri-apps/api/core"`.
107→ * Works in both Tauri and plain-browser environments.
108→ */
109→export async function invoke<T>(cmd: string, args?: Record<string, unknown>): Promise<T> {
110→  if (isTauri) {
111→    return tauriInvoke<T>(cmd, args);
112→  }
113→  return httpInvoke<T>(cmd, args);
114→}
