146→/**
147→ * Groups sessions by date category, sorted by mod_time descending within each group.
148→ */
149→export function groupByDate<T extends { mod_time: string }>(
150→  items: T[],
151→): { category: string; items: T[] }[] {
152→  const now = new Date();
153→  const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
154→  const yesterdayStart = new Date(todayStart.getTime() - 86400000);
155→  const weekStart = new Date(todayStart.getTime() - 7 * 86400000);
156→  const monthStart = new Date(todayStart.getTime() - 30 * 86400000);
157→
158→  const groups: Record<string, T[]> = {};
159→  const order = ["Today", "Yesterday", "This Week", "This Month", "Older"];
160→
161→  for (const item of items) {
162→    const d = new Date(item.mod_time);
163→    let cat: string;
164→    if (d >= todayStart) cat = "Today";
165→    else if (d >= yesterdayStart) cat = "Yesterday";
166→    else if (d >= weekStart) cat = "This Week";
167→    else if (d >= monthStart) cat = "This Month";
168→    else cat = "Older";
169→
170→    (groups[cat] ??= []).push(item);
171→  }
172→
173→  // Sort each group by mod_time descending (most recent first)
174→  for (const cat of order) {
175→    if (groups[cat]) {
176→      groups[cat].sort((a, b) => new Date(b.mod_time).getTime() - new Date(a.mod_time).getTime());
177→    }
178→  }
179→
180→  return order
181→    .filter((cat) => groups[cat]?.length)
182→    .map((category) => ({ category, items: groups[category] }));
183→}
