185→/**
186→ * Truncates text to maxLen, appending ellipsis if needed.
187→ */
188→export function truncate(text: string, maxLen: number): string {
189→  if (text.length <= maxLen) return text;
190→  return text.slice(0, maxLen - 1) + "\u2026";
191→}
192→
193→/**
194→ * Returns the first non-empty line of text.
195→ */
196→export function firstLine(text: string): string {
197→  const idx = text.indexOf("\n");
198→  return idx === -1 ? text : text.slice(0, idx);
199→}
