201→/**
202→ * Pretty-prints a JSON string. Returns the original string on parse failure.
203→ */
204→export function formatJson(input: string): string {
205→  try {
206→    return JSON.stringify(JSON.parse(input), null, 2);
207→  } catch {
208→    return input;
209→  }
210→}
