212→/**
213→ * Extract the encoded project directory key from a session path.
214→ */
215→export function projectKey(path: string): string {
216→  const match = path.match(/[/\\]\.claude[/\\]projects[/\\]([^/\\]+)/);
217→  return match ? match[1] : "unknown";
218→}
219→
220→/**
221→ * Decode a Claude projects directory key (e.g. "-Users-yang-liu-Envato-others-my-project")
222→ * back to a path and return the last segment via shortPath.
223→ */
224→export function projectDisplayName(key: string): string {
225→  const path = key.replace(/^-/, "/").replaceAll("-", "/");
226→  return shortPath(path) || key;
227→}
