 35→export function DetailItem({
 36→  ref,
 37→  item,
 38→  index,
 39→  isSelected,
 40→  isExpanded,
 41→  isAgentActive,
 42→  onToggle,
 43→  onToggleExpand,
 44→  onSelect,
 45→}: DetailItemProps) {
 46→  const icon = getItemIcon(item);
 47→  const name = getItemName(item);
 48→  const summary = getItemSummary(item);
 49→  const teamClr = item.team_color ? getTeamColor(item.team_color) : undefined;
 50→  const hasAgentMessages = item.subagent_messages.length > 0;
 51→  const subagentStats = useSubagentStats(item);
 52→  const [popout, setPopout] = useState(false);
 53→
 54→  return (
 55→    <div
 56→      ref={ref}
 57→      className={`detail-item${isSelected ? " detail-item--selected" : ""}${item.tool_error ? " detail-item--error" : ""}${isAgentActive ? " detail-item--agent-active" : ""}`}
 58→      style={
 59→        isAgentActive && teamClr
 60→          ? { background: `${teamClr}12`, borderLeftColor: teamClr }
 61→          : undefined
 62→      }
 63→      onDoubleClick={() => {
 64→        if (hasAgentMessages) {
 65→          onToggle(index, item);
 66→        } else if (item.subagent_prompt) {
 67→          onToggleExpand(index);
 68→        }
 69→      }}
 70→    >
 71→      <div
 72→        className="detail-item__header"
 73→        onClick={() => {
 74→          onSelect(index);
 75→          onToggle(index, item);
 76→        }}
 77→      >
 78→        <span
 79→          className={`detail-item__chevron${isExpanded ? " detail-item__chevron--expanded" : ""}${hasAgentMessages ? " detail-item__chevron--panel" : ""}`}
 80→          style={hasAgentMessages && teamClr ? { color: teamClr } : undefined}
 81→        >
 82→          {hasAgentMessages ? <PanelChevronIcon /> : <ChevronIcon />}
 83→        </span>
 84→        <span className="detail-item__icon">{icon}</span>
 85→        <span className="detail-item__name" style={teamClr ? { color: teamClr } : undefined}>
 86→          {name}
 87→        </span>
 88→        <span className="detail-item__summary">{summary}</span>
 89→        {item.is_orphan && <span className="detail-item__orphan-badge">orphan</span>}
 90→        {item.agent_id && <span className="detail-item__agent-id">{item.agent_id}</span>}
 91→        <span className="detail-item__right">
 92→          {item.duration_ms > 0 && (
 93→            <span className="detail-item__duration">{formatDuration(item.duration_ms)}</span>
 94→          )}
 95→          {item.subagent_ongoing && <OngoingDots />}
 96→          {(hasAgentMessages || item.subagent_prompt) && (
 97→            <button
 98→              className="message__detail-btn"
 99→              onClick={(e) => {
100→                e.stopPropagation();
101→                if (hasAgentMessages) {
102→                  onSelect(index);
103→                  onToggle(index, item);
104→                } else {
105→                  onToggleExpand(index);
106→                }
107→              }}
108→            >
109→              Detail <ForwardIcon />
110→            </button>
111→          )}
112→          {isExpanded && (
113→            <button
114→              className="detail-item__popout-btn"
115→              onClick={(e) => {
116→                e.stopPropagation();
117→                setPopout(true);
118→              }}
119→              title="Pop out to larger view"
120→            >
121→              <PopoutIcon />
122→            </button>
123→          )}
124→        </span>
125→      </div>
126→      {item.subagent_prompt && (
127→        <div
128→          className={`detail-item__prompt-preview${isExpanded ? " detail-item__prompt-preview--expanded" : ""}`}
129→          onClick={(e) => {
130→            e.stopPropagation();
131→            onToggleExpand(index);
132→          }}
133→        >
134→          {firstLine(item.subagent_prompt)}
135→        </div>
136→      )}
137→      {subagentStats && <StatsBar stats={subagentStats} />}
138→      {isExpanded && <DetailItemBody item={item} />}
139→      {popout && (
140→        <PopoutModal
141→          onClose={() => setPopout(false)}
142→          header={
143→            <>
144→              <span className="popout-modal__icon">{icon}</span>
145→              <span className="popout-modal__name">{name}</span>
146→              {item.tool_summary && (
147→                <span className="popout-modal__summary">{item.tool_summary}</span>
148→              )}
149→              {item.agent_id && <span className="popout-modal__agent-id">{item.agent_id}</span>}
150→              <span className="popout-modal__right">
151→                {item.duration_ms > 0 && <span>{formatDuration(item.duration_ms)}</span>}
