232→          )}
233→        </div>
234→      );
235→    case "TeammateMessage":
236→      return (
237→        <div className="detail-item__body">
238→          <div className="detail-item__text">{item.text}</div>
239→        </div>
240→      );
241→    case "HookEvent":
242→      return (
243→        <div className="detail-item__body">
244→          <div className="detail-item__section">
245→            <div className="detail-item__section-title">Hook</div>
246→            <div className="detail-item__text detail-item__text--mono">
