271→export function getItemIcon(item: DisplayItem): React.ReactNode {
272→  switch (item.item_type) {
273→    case "Thinking":
274→      return <ThinkingIcon />;
275→    case "Output":
276→      return <OutputIcon />;
277→    case "ToolCall":
278→      return item.tool_error ? (
279→        <WarningIcon />
280→      ) : (
281→        (toolCategoryIcons[item.tool_category] ?? toolCategoryIcons.Other)
282→      );
283→    case "Subagent":
284→      return <ClaudeIcon className="detail-item__claude-icon" />;
285→    case "TeammateMessage":
286→      return <ClaudeIcon className="detail-item__claude-icon" />;
287→    case "HookEvent":
288→      return <HookIcon />;
289→    default:
290→      return <DefaultItemIcon />;
291→  }
292→}
