294→export function getItemName(item: DisplayItem): string {
295→  switch (item.item_type) {
296→    case "Thinking":
297→      return "Thinking";
298→    case "Output":
299→      return "Output";
300→    case "ToolCall":
301→      return item.tool_name || "Tool";
302→    case "Subagent":
303→      return item.subagent_type || "Subagent";
304→    case "TeammateMessage":
305→      return item.team_member_name || "Teammate";
306→    case "HookEvent":
307→      return item.hook_event || "Hook";
308→    default:
309→      return item.item_type;
310→  }
311→}
312→
313→export function getItemSummary(item: DisplayItem): string {
314→  switch (item.item_type) {
315→    case "ToolCall":
316→      return item.tool_summary || "";
317→    case "Subagent":
318→      return item.subagent_desc || "";
319→    case "TeammateMessage":
320→      return item.text ? item.text.slice(0, 100) : "";
321→    case "Thinking":
322→      return item.text
323→        ? item.text.slice(0, 80) + (item.text.length > 80 ? "\u2026" : "")
324→        : "Content not recorded";
325→    case "Output":
326→      return item.text ? item.text.slice(0, 80) + (item.text.length > 80 ? "\u2026" : "") : "";
327→    case "HookEvent":
328→      return item.hook_name
329→        ? `${item.hook_name}${item.hook_command ? ": " + truncate(item.hook_command, 60) : ""}`
330→        : item.hook_command
331→          ? truncate(item.hook_command, 80)
332→          : "";
333→    default:
334→      return "";
335→  }
336→}
