17→function ensureSse(): EventSource {
18→  if (!sseSource || sseSource.readyState === EventSource.CLOSED) {
19→    sseSource = new EventSource(`${API_BASE}/api/events`);
20→  }
21→  sseRefCount++;
22→  return sseSource;
23→}
24→
25→function releaseSse(): void {
26→  sseRefCount--;
27→  if (sseRefCount <= 0 && sseSource) {
28→    sseSource.close();
29→    sseSource = null;
30→    sseRefCount = 0;
31→  }
32→}
33→
34→export async function listen<T>(
35→  event: string,
36→  handler: (event: { payload: T }) => void,
37→): Promise<UnlistenFn> {
38→  if (isTauri) {
39→    return tauriListen<T>(event, handler);
40→  }
41→
42→  const source = ensureSse();
43→  const onMessage = (e: MessageEvent) => {
44→    try {
45→      const payload = JSON.parse(e.data) as T;
46→      handler({ payload });
47→    } catch {
48→      // ignore malformed events
49→    }
50→  };
51→  source.addEventListener(event, onMessage as EventListener);
52→
53→  return () => {
54→    source.removeEventListener(event, onMessage as EventListener);
55→    releaseSse();
56→  };
57→}
