  8→  OutputIcon,
  9→  DurationIcon,
 10→  AgentsIcon,
 11→  SpawnIcon,
 12→} from "./Icons";
 13→
 14→export interface Stats {
 15→  tokens: number;
 16→  toolCount: number;
 17→  thinkingCount: number;
 18→  outputCount: number;
 19→  durationMs: number;
 20→  agentCount: number;
 21→  spawnCount: number;
 22→}
 23→
 24→export function statsFromMessage(msg: DisplayMessage): Stats {
 25→  const agentCount = msg.items.filter(
 26→    (it) => it.item_type === "Subagent" || it.subagent_messages.length > 0,
 27→  ).length;
 28→  return {
 29→    tokens: msg.tokens_raw,
 30→    toolCount: msg.tool_call_count,
 31→    thinkingCount: msg.thinking_count,
 32→    outputCount: msg.output_count,
 33→    durationMs: msg.duration_ms,
 34→    agentCount,
 35→    spawnCount: msg.teammate_spawns,
 36→  };
 37→}
 38→
 39→export function statsFromSubagentMessages(messages: DisplayMessage[]): Stats {
 40→  let tokens = 0;
 41→  let toolCount = 0;
 42→  let thinkingCount = 0;
 43→  let outputCount = 0;
 44→  let agentCount = 0;
 45→  for (const m of messages) {
 46→    tokens += m.tokens_raw;
 47→    toolCount += m.tool_call_count;
 48→    thinkingCount += m.thinking_count;
 49→    outputCount += m.output_count;
 50→    agentCount += m.items.filter(
 51→      (it) => it.item_type === "Subagent" || it.subagent_messages.length > 0,
 52→    ).length;
 53→  }
 54→  return {
 55→    tokens,
 56→    toolCount,
 57→    thinkingCount,
 58→    outputCount,
 59→    durationMs: 0,
 60→    agentCount,
 61→    spawnCount: 0,
 62→  };
 63→}
 64→
 65→export function useSubagentStats(item: DisplayItem): Stats | null {
 66→  return useMemo(() => {
 67→    if (item.subagent_messages.length === 0) return null;
 68→    return statsFromSubagentMessages(item.subagent_messages);
 69→  }, [item.subagent_messages]);
 70→}
 71→
 72→function hasAny(s: Stats): boolean {
 73→  return (
 74→    s.tokens > 0 ||
 75→    s.toolCount > 0 ||
 76→    s.thinkingCount > 0 ||
 77→    s.outputCount > 0 ||
 78→    s.durationMs > 0 ||
 79→    s.agentCount > 0 ||
 80→    s.spawnCount > 0
 81→  );
 82→}
 83→
 84→export function StatsBar({ stats }: { stats: Stats }) {
 85→  if (!hasAny(stats)) return null;
 86→
 87→  return (
 88→    <div className="message__stats">
 89→      {stats.tokens > 0 && (
 90→        <span
 91→          className={`message__stat${stats.tokens > 150000 ? " message__stat--tokens-high" : ""}`}
 92→        >
 93→          <span className="message__stat-icon">
 94→            <TokensIcon />
 95→          </span>
 96→          {formatTokens(stats.tokens)} tok
 97→        </span>
 98→      )}
 99→      {stats.toolCount > 0 && (
100→        <span className="message__stat">
101→          <span className="message__stat-icon">
102→            <ToolsIcon />
103→          </span>
104→          {stats.toolCount} tool{stats.toolCount > 1 ? "s" : ""}
105→        </span>
106→      )}
107→      {stats.thinkingCount > 0 && (
108→        <span className="message__stat">
109→          <span className="message__stat-icon">
110→            <ThinkingIcon />
111→          </span>
112→          {stats.thinkingCount} think
113→        </span>
114→      )}
115→      {stats.outputCount > 0 && (
116→        <span className="message__stat">
117→          <span className="message__stat-icon">
118→            <OutputIcon />
119→          </span>
120→          {stats.outputCount} out
121→        </span>
122→      )}
123→      {stats.durationMs > 0 && (
124→        <span className="message__stat">
125→          <span className="message__stat-icon">
126→            <DurationIcon />
127→          </span>
128→          {formatDuration(stats.durationMs)}
129→        </span>
130→      )}
131→      {stats.agentCount > 0 && (
132→        <span className="message__stat message__stat--agents">
133→          <span className="message__stat-icon">
134→            <AgentsIcon />
135→          </span>
136→          {stats.agentCount} agent{stats.agentCount > 1 ? "s" : ""}
137→        </span>
138→      )}
139→      {stats.spawnCount > 0 && (
140→        <span className="message__stat">
141→          <span className="message__stat-icon">
142→            <SpawnIcon />
143→          </span>
144→          {stats.spawnCount} spawn{stats.spawnCount > 1 ? "s" : ""}
145→        </span>
146→      )}
147→    </div>
148→  );
149→}
