 25→/// Shared state for axum handlers.
 26→#[derive(Clone)]
 27→pub struct HttpState {
 28→    pub app: AppHandle,
 29→}
 30→
 31→/// Start the HTTP API server on port 11423.
 32→pub async fn start_http_server(app: AppHandle) {
 33→    let state = Arc::new(HttpState { app });
 34→
 35→    let router = Router::new()
 36→        .route("/api/settings", get(api_get_settings))
 37→        .route("/api/settings/dir", post(api_set_projects_dir))
 38→        .route("/api/project-dirs", get(api_get_project_dirs))
 39→        .route("/api/sessions", get(api_discover_sessions))
 40→        .route("/api/session/load", post(api_load_session))
 41→        .route("/api/session/meta", get(api_get_session_meta))
 42→        .route("/api/session/watch", post(api_watch_session))
 43→        .route("/api/session/unwatch", post(api_unwatch_session))
 44→        .route("/api/picker/watch", post(api_watch_picker))
 45→        .route("/api/picker/unwatch", post(api_unwatch_picker))
 46→        .route("/api/git-info", get(api_get_git_info))
 47→        .route("/api/debug-log", get(api_get_debug_log))
 48→        .route("/api/events", get(api_events))
 49→        .layer(CorsLayer::permissive())
 50→        .with_state(state);
 51→
 52→    let listener = match tokio::net::TcpListener::bind("127.0.0.1:11423").await {
 53→        Ok(l) => l,
 54→        Err(e) => {
 55→            eprintln!("HTTP API: failed to bind port 11423: {e}");
 56→            return;
 57→        }
 58→    };
 59→    eprintln!("HTTP API: listening on http://127.0.0.1:11423");
 60→
 61→    if let Err(e) = axum::serve(listener, router).await {
 62→        eprintln!("HTTP API: server error: {e}");
 63→    }
 64→}
 65→
 66→// ---------------------------------------------------------------------------
 67→// Helpers
 68→// ---------------------------------------------------------------------------
 69→
 70→fn app_state(state: &HttpState) -> &AppState {
 71→    state.app.state::<AppState>().inner()
 72→}
 73→
 74→fn err_response(status: axum::http::StatusCode, msg: String) -> Response {
 75→    (status, Json(serde_json::json!({ "error": msg }))).into_response()
 76→}
 77→
 78→fn ok_json<T: serde::Serialize>(val: &T) -> Response {
 79→    Json(val).into_response()
 80→}
 81→
 82→// ---------------------------------------------------------------------------
 83→// Settings
 84→// ---------------------------------------------------------------------------
 85→
 86→async fn api_get_settings(State(state): State<Arc<HttpState>>) -> Response {
 87→    let app_state = app_state(&state);
 88→    let guard = match app_state.settings.lock() {
 89→        Ok(g) => g,
 90→        Err(e) => {
 91→            return err_response(axum::http::StatusCode::INTERNAL_SERVER_ERROR, e.to_string())
 92→        }
 93→    };
 94→    let default_dir = crate::commands::settings::platform_default_dir();
 95→    ok_json(&crate::commands::settings::SettingsResponse {
 96→        projects_dir: guard.projects_dir.clone(),
 97→        default_dir,
 98→    })
 99→}
