15→    let web_only = args.iter().any(|a| a == "--web");
16→    let headless = args.iter().any(|a| a == "--headless");
17→
18→    tauri::Builder::default()
19→        .plugin(tauri_plugin_fs::init())
20→        .plugin(tauri_plugin_opener::init())
21→        .manage(state::AppState::new())
22→        .invoke_handler(tauri::generate_handler![
23→            commands::session::load_session,
24→            commands::session::get_session_meta,
25→            commands::session::watch_session,
26→            commands::session::unwatch_session,
27→            commands::session::get_project_dirs,
28→            commands::picker::discover_sessions,
29→            commands::picker::watch_picker,
30→            commands::picker::unwatch_picker,
31→            commands::git::get_git_info,
32→            commands::debug::get_debug_log,
33→            commands::settings::get_settings,
34→            commands::settings::set_projects_dir,
35→            switch_to_browser,
36→        ])
37→        .setup(move |app| {
38→            let handle = app.handle().clone();
39→            tauri::async_runtime::spawn(http_api::start_http_server(handle));
40→
41→            if headless {
42→                eprintln!("Headless mode: HTTP API on http://127.0.0.1:11423");
43→            } else if web_only {
44→                eprintln!("Web mode: opening http://localhost:1420 in your browser...");
45→                let _ = tauri_plugin_opener::open_url("http://localhost:1420", None::<&str>);
