48→                if let Some(w) = app.get_webview_window("main") {
49→                    let _ = w.show();
50→                }
51→            }
52→
53→            Ok(())
54→        })
55→        .run(tauri::generate_context!())
56→        .expect("error while running tauri application");
57→}
