  1→// Format utilities — ported from format.go
  2→// Pure shared utilities are re-exported from shared/format.ts.
  3→
  4→import type { DisplayMessage } from "../types";
  5→export { formatTokens } from "../../shared/format";
  6→
  7→/**
  8→ * Turns "claude-opus-4-6" into "opus4.6".
  9→ */
 10→export function shortModel(m: string): string {
 11→  m = m.replace(/^claude-/, "");
 12→  const dashIdx = m.indexOf("-");
 13→  if (dashIdx === -1) return m;
 14→
 15→  const family = m.slice(0, dashIdx);
 16→  const rest = m.slice(dashIdx + 1);
 17→  // Keep major-minor only, drop patch/build metadata
 18→  const vParts = rest.split("-");
 19→  let version = vParts[0];
 20→  if (vParts.length >= 2) {
 21→    version = vParts[0] + "." + vParts[1];
 22→  }
 23→  return family + version;
 24→}
 25→
 26→// Claude API pricing per million tokens (USD).
 27→// Model-specific rates; we pick by the model string prefix.
 28→const MODEL_PRICING: {
 29→  prefix: string;
 30→  input: number;
 31→  output: number;
 32→  cacheRead: number;
 33→  cacheWrite: number;
 34→}[] = [
 35→  { prefix: "opus", input: 5, output: 25, cacheRead: 0.5, cacheWrite: 6.25 },
 36→  { prefix: "sonnet", input: 3, output: 15, cacheRead: 0.3, cacheWrite: 3.75 },
 37→  { prefix: "haiku", input: 1, output: 5, cacheRead: 0.1, cacheWrite: 1.25 },
 38→];
 39→
 40→function pricingForModel(model: string) {
 41→  const m = model.toLowerCase();
 42→  return MODEL_PRICING.find((p) => m.includes(p.prefix)) ?? MODEL_PRICING[1]; // default sonnet
 43→}
 44→
 45→/**
 46→ * Estimates USD cost from token breakdown and model string.
 47→ */
 48→export function estimateCost(
 49→  input: number,
 50→  output: number,
 51→  cacheRead: number,
 52→  cacheWrite: number,
 53→  model: string,
 54→): number {
 55→  const p = pricingForModel(model);
 56→  return (
 57→    (input * p.input + output * p.output + cacheRead * p.cacheRead + cacheWrite * p.cacheWrite) /
 58→    1_000_000
 59→  );
 60→}
 61→
 62→/**
 63→ * Formats a dollar amount: 0.0023 -> "0.00", 1.23 -> "1.23", 12.5 -> "12.50"
 64→ */
 65→export function formatCost(usd: number): string {
 66→  return usd.toFixed(2);
 67→}
 68→
 69→/**
 70→ * Formats milliseconds into human-readable duration.
 71→ */
 72→export function formatDuration(ms: number): string {
 73→  const secs = ms / 1000;
 74→  if (secs >= 60) {
 75→    const mins = Math.floor(secs / 60);
 76→    const rem = Math.floor(secs % 60);
 77→    return `${mins}m ${rem}s`;
 78→  }
 79→  if (secs >= 10) return `${Math.round(secs)}s`;
 80→  return `${secs.toFixed(1)}s`;
 81→}
 82→
 83→/**
 84→ * Returns the project display name from a cwd path.
 85→ * Extracts the last path segment.
 86→ */
 87→export function shortPath(cwd: string, _gitBranch?: string): string {
 88→  if (!cwd) return "";
 89→  const parts = cwd.split("/").filter(Boolean);
 90→  return parts[parts.length - 1] ?? cwd;
 91→}
 92→
 93→/**
 94→ * Returns a human-readable label for a permission mode.
 95→ */
 96→export function shortMode(mode: string): string {
 97→  switch (mode) {
 98→    case "default":
 99→      return "default";
100→    case "acceptEdits":
101→      return "auto-edit";
102→    case "bypassPermissions":
103→      return "yolo";
104→    case "plan":
105→      return "plan";
106→    default:
107→      return mode;
108→  }
109→}
110→
111→/**
112→ * Returns context window usage percentage (0-100).
113→ * Returns -1 if no usage data is available.
114→ */
115→export function contextPercent(msgs: DisplayMessage[]): number {
116→  const contextWindowSize = 1_000_000;
117→  for (let i = msgs.length - 1; i >= 0; i--) {
118→    if (msgs[i].role === "claude" && msgs[i].context_tokens > 0) {
119→      const pct = Math.floor((msgs[i].context_tokens * 100) / contextWindowSize);
120→      return Math.min(pct, 100);
121→    }
122→  }
123→  return -1;
124→}
125→
126→/**
127→ * Formats a timestamp as yyyy-mm-dd hh:mm:ss.
128→ */
129→export function formatExactTime(ts: string): string {
130→  if (!ts) return "";
131→  try {
132→    const d = new Date(ts);
133→    if (isNaN(d.getTime())) return "";
134→    const yyyy = d.getFullYear();
135→    const mm = String(d.getMonth() + 1).padStart(2, "0");
136→    const dd = String(d.getDate()).padStart(2, "0");
137→    const hh = String(d.getHours()).padStart(2, "0");
138→    const mi = String(d.getMinutes()).padStart(2, "0");
139→    const ss = String(d.getSeconds()).padStart(2, "0");
140→    return `${yyyy}-${mm}-${dd} ${hh}:${mi}:${ss}`;
141→  } catch {
142→    return "";
143→  }
144→}
145→
146→/**
147→ * Groups sessions by date category, sorted by mod_time descending within each group.
148→ */
